router.get("/api/controlador/meu-ip", (req: Request, res: Response) => {
  const clientInfo = (req as any).clientInfo;

  res.json({
    success: true,
    message: "Informações de geolocalização",
    data: {
      ip: clientInfo.ip,
      geolocation: clientInfo.geo
        ? {
            country: clientInfo.geo.country,
            region: clientInfo.geo.region,
            city: clientInfo.geo.city,
            coordinates: clientInfo.geo.ll,
            latitude: clientInfo.geo.ll?.[0],
            longitude: clientInfo.geo.ll?.[1],
            timezone: clientInfo.geo.timezone,
            metroCode: clientInfo.geo.metro,
            areaCode: clientInfo.geo.area,
          }
        : null,
      userAgent: clientInfo.userAgent,
    },
  });
});

